import React, { useState, useMemo } from "react";
import {
  Container,
  Row,
  Col,
  Form,
  Button,
  Card,
  ListGroup,
} from "react-bootstrap";
import { useProvider } from "./useProvider";

const Movies = () => {
  const { producers, movies, directors, stars } = useProvider();
  const producerName = [...new Set(producers?.map((p) => p.name))];

  const genres = [...new Set(movies?.flatMap((m) => m.genres || []))];

  return (
    <Container>
      <h1 style={{ display: "flex", justifyContent: "center" }}>
        React Application
      </h1>
      <hr />
      <div style={{ display: "flex", gap: "20px", justifyContent: "center" }}>
        {genres?.map((g) => (
          <a key={g} href="/">
            {g}
          </a>
        ))}
      </div>
      <hr />
      <Row>
        <Col xs={2}>
          <h2>Producers</h2>

          {producerName?.map((p) => (
            <li key={p} style={{ marginLeft: "40px" }}>
              <a href="/">{p}</a>
            </li>
          ))}
        </Col>

        <Col xs={10}>
          <h2 style={{ display: "flex", justifyContent: "center" }}>
            List of Movies
          </h2>
          <table style={{ width: "100%" }}>
            <thead>
              <tr>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  ID
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Title
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Release
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Description
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Producer
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Director
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Genres
                </th>
                <th
                  style={{
                    padding: "10px",
                    textAlign: "left",
                    fontWeight: "bold",
                  }}
                >
                  Stars
                </th>
              </tr>
            </thead>
            <tbody>
              {movies?.map((movie, index) => (
                <tr
                  key={movie.id}
                  style={{
                    borderBottom: "1px solid #ddd",
                    backgroundColor: index % 2 === 0 ? "#f9f9f9" : "#fff",
                  }}
                >
                  <td style={{ padding: "10px" }}>{index + 1}</td>

                  <td style={{ padding: "10px" }}>{movie.title}</td>

                  <td style={{ padding: "10px" }}>
                    {new Date(movie.release).toLocaleDateString("en-US", {
                      month: "2-digit",
                      day: "2-digit",
                      year: "2-digit",
                    })}
                  </td>

                  <td style={{ padding: "10px" }}>{movie.description}</td>

                  <td style={{ padding: "10px" }}>
                    {producers?.find((p) => p.id === movie.producer)?.name}
                  </td>

                  <td style={{ padding: "10px" }}>
                    {directors?.find((d) => d.id === movie.director)?.fullname}
                  </td>

                  <td style={{ padding: "10px" }}>
                    {movie.genres?.map((g, i) => (
                      <div key={i}>{g}</div>
                    ))}
                  </td>

                  <td style={{ padding: "10px" }}>
                    {movies
                      .stars?.((ms) => ms.id === stars.id)
                      .map((s, i) => (
                        <div key={ms.stars}>
                          {i + 1} - {ms.stars.fullname}
                        </div>
                      ))}
                    <a href="/" style={{ color: "#0066cc", fontSize: "12px" }}>
                      Add stars
                    </a>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </Col>
      </Row>
    </Container>
  );
};

export default Movies;
